import subprocess
import sys
from pathlib import Path
from typing import Optional


def run_git(*args: str, cwd: Optional[Path] = None, check: bool = True) -> str:
    """Run a git command and return its stdout, stripped."""
    cmd = ["git"] + list(args)
    result = subprocess.run(
        cmd,
        cwd=cwd,
        capture_output=True,
        text=True,
        check=check,
    )
    return result.stdout.strip()


def get_current_branch(repo: Path) -> str:
    """Return the name of the currently checked-out branch."""
    return run_git("rev-parse", "--abbrev-ref", "HEAD", cwd=repo)


def has_uncommitted_changes(repo: Path) -> bool:
    """Return True if the working tree or index has modifications."""
    return bool(run_git("status", "--porcelain", cwd=repo))


def get_log(repo: Path, n: int = 10) -> list[dict]:
    """Return the last n commits as a list of dicts."""
    fmt = "%H|%an|%ae|%ad|%s"
    output = run_git("log", f"-{n}", f"--pretty=format:{fmt}", cwd=repo)
    commits = []
    for line in output.splitlines():
        sha, author, email, date, subject = line.split("|", 4)
        commits.append({
            "sha": sha[:8],
            "author": author,
            "email": email,
            "date": date,
            "subject": subject,
        })
    return commits


def create_commit(
    repo: Path, message: str, all_changes: bool = True
) -> str:
    """Stage all changes (or rely on pre-staged) and create a commit.

    Returns the full SHA of the new commit.
    """
    if all_changes:
        run_git("add", "-A", cwd=repo)
    run_git("commit", "-m", message, cwd=repo)
    return run_git("rev-parse", "HEAD", cwd=repo)


def push_branch(
    repo: Path, remote: str = "origin", branch: Optional[str] = None
) -> None:
    """Push the current (or named) branch to the remote."""
    if branch is None:
        branch = get_current_branch(repo)
    run_git("push", remote, branch, cwd=repo)


if __name__ == "__main__":
    repo = Path(sys.argv[1]) if len(sys.argv) > 1 else Path.cwd()
    print(f"Branch : {get_current_branch(repo)}")
    print(f"Dirty  : {has_uncommitted_changes(repo)}")
    print("\nRecent commits:")
    for c in get_log(repo, n=5):
        print(f"  {c['sha']}  {c['subject'][:60]}  ({c['author']})")
